import test from 'node:test';
import assert from 'node:assert/strict';
import { decodeBase64Url } from '../src/base64url.mjs';
import { parseBlobLocator } from '../src/blob-locator.mjs';

test('rejects aliases with nonzero unused bits in the last character', () => {
  const canonical = 'AAAAAAAAAAAAAAAAAAAAAA';
  const alias = 'AAAAAAAAAAAAAAAAAAAAAB';
  assert.deepEqual(Buffer.from(alias, 'base64url'), Buffer.from(canonical, 'base64url'));

  assert.throws(() => decodeBase64Url(alias), /canonical|base64url/i);
  assert.throws(() => parseBlobLocator('images:' + alias), /canonical|base64url/i);
});
